	/// Get Category Games
	pub async fn games(&self, category_name: String) -> Result<CategoryGamesResponse, LolzteamError> {
		let path = format!("/{category_name}/games");
		self.http.request("GET", &path, None, None).await
	}

	/// Get Category Search Params
	pub async fn params(&self, category_name: String) -> Result<CategoryParamsResponse, LolzteamError> {
		let path = format!("/{category_name}/params");
		self.http.request("GET", &path, None, None).await
	}
